from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a city (or related entities) into a single fluent sentence."""
    if not triples:
        return ""

    # Identify the main subject (most common subject in triples)
    subjects = [t.subject for t in triples]
    main_subject = max(set(subjects), key=subjects.count) if subjects else ""

    # Build sentence parts with proper connectors
    main_clause_parts = []
    relative_clauses = []

    # Start with main subject and type if available
    for t in triples:
        if t.predicate == "type":
            main_clause_parts.append(f"{main_subject} is a {t.object}")
            break
    else:
        main_clause_parts.append(main_subject)

    # Process all triples in a single pass for efficiency
    location_parts = []
    for t in triples:
        if t.predicate == "country":
            location_parts.append(f"in {t.object}")
        elif t.predicate == "state":
            location_parts.append(f"located in the state of {t.object}")
        elif t.predicate == "isPartOf":
            location_parts.append(f"part of {t.object}")
        elif t.predicate == "capital":
            relative_clauses.append(f"where the capital is {t.object}")
        elif t.predicate == "largestCity":
            relative_clauses.append(f"with the largest city being {t.object}")
        elif t.predicate == "countySeat":
            relative_clauses.append(f"with the county seat in {t.object}")
        elif t.predicate == "populationTotal":
            main_clause_parts.append(f" with a total population of {t.object}")
        elif t.predicate == "populationDensity":
            main_clause_parts.append(f" and a population density of {t.object}")
        elif t.predicate == "populationMetro":
            main_clause_parts.append(f" in a metro area of {t.object}")
        elif t.predicate == "demonym":
            main_clause_parts.append(f" whose residents are called {t.object}")
        elif t.predicate == "areaTotal":
            main_clause_parts.append(f" covering a total area of {t.object}")
        elif t.predicate == "areaOfLand":
            main_clause_parts.append(f" with a land area of {t.object}")
        elif t.predicate == "areaOfWater":
            main_clause_parts.append(f" and water area of {t.object}")
        elif t.predicate == "leader":
            main_clause_parts.append(f" and is led by {t.object}")
        elif t.predicate == "governmentType":
            main_clause_parts.append(f" operating under a {t.object} government")
        elif t.predicate == "elevationAboveTheSeaLevel":
            main_clause_parts.append(f" at an elevation of {t.object}")
        elif t.predicate == "timeZone":
            main_clause_parts.append(f" in the {t.object} time zone")
        elif t.predicate == "utcOffset":
            main_clause_parts.append(f" with UTC offset {t.object}")
        elif t.predicate == "areaCode":
            main_clause_parts.append(f" using area code(s) {t.object}")
        elif t.predicate == "postalCode":
            main_clause_parts.append(f" with postal code(s) {t.object}")
        elif t.predicate == "language":
            main_clause_parts.append(f" where {t.object} is spoken")
        elif t.predicate == "ethnicGroup":
            main_clause_parts.append(f" including {t.object}")

    # Combine all parts
    if location_parts:
        main_clause_parts.insert(1, f", {', '.join(location_parts)}")

    # Build final sentence
    sentence = "".join(main_clause_parts) + "."

    # Add relative clauses if any
    if relative_clauses:
        sentence = sentence[:-1] + ", " + ", ".join(relative_clauses) + "."

    return sentence

# EVOLVE-BLOCK-END

